import Link from 'next/link'
import { ArrowRight, Sparkles, Search, Users } from 'lucide-react'
import { createClient } from '@/lib/supabase/server'
import { Navbar } from '@/components/Navbar'
import { Footer } from '@/components/Footer'
import { PostCard } from '@/components/PostCard'
import { SearchBar } from '@/components/SearchBar'
import { TagsCloud } from '@/components/TagsCloud'
import { FloatingActionButton } from '@/components/ui/FloatingActionButton'
import { ActivityFeedCompact } from '@/components/ActivityFeed'
import { SocialProofBanner } from '@/components/SocialProofBanner'
import { SuggestedPostsCarousel } from '@/components/SuggestedPosts'
import { RelatedAuthors } from '@/components/RelatedAuthors'
import { OnboardingModal } from '@/components/OnboardingModal'

import { getTranslations, setRequestLocale } from 'next-intl/server'

export const dynamic = 'force-dynamic';

export default async function Home({
  params
}: {
  params: Promise<{ locale: string }>
}) {
  const { locale } = await params;
  setRequestLocale(locale);

  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  const t = await getTranslations({ locale, namespace: 'Landing' });

  // Fetch recent posts for feed preview (for logged-in users)
  let recentPosts: any[] = []
  if (user) {
    const { data } = await supabase
      .from('posts')
      .select(`
        *,
        author:users!posts_author_id_fkey(id, name, email)
      `)
      .order('created_at', { ascending: false })
      .limit(6)

    recentPosts = data || []
  }

  return (
    <div className="min-h-screen flex flex-col bg-background dark:bg-dark-bg">
      <Navbar user={user} />

      <main className="flex-1">
        {user ? (
          <>
            {/* Onboarding Modal for New Users */}
            <OnboardingModal
              userId={user.id}
              userEmail={user.email || ''}
              userName={user.user_metadata?.name}
            />

            {/* Feed Section for Logged-in Users */}
            <section className="section pt-20 md:pt-24">
              <div className="container-custom max-w-7xl">
                {/* Social Proof Banner */}
                <div className="mb-8">
                  <SocialProofBanner />
                </div>

                {/* Search Bar */}
                <div className="mb-12 flex justify-center">
                  <SearchBar />
                </div>

                {/* Tags Cloud */}
                <div className="mb-16">
                  <h2 className="text-2xl font-display font-semibold text-center mb-8 text-primary dark:text-dark-text">
                    {t('popularTopics')}
                  </h2>
                  <TagsCloud />
                </div>

                {/* Two-column layout: Main content + Sidebar */}
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                  {/* Main Content Column */}
                  <div className="lg:col-span-2 space-y-12">
                    {/* Recent Posts */}
                    <div>
                      <div className="flex items-center justify-between mb-8">
                        <h2 className="text-3xl font-display font-semibold text-primary dark:text-dark-text">
                          {t('recentResearch')}
                        </h2>
                        <Link
                          href="/feed"
                          className="text-primary dark:text-accent-light hover:text-accent dark:hover:text-accent font-medium flex items-center gap-2"
                        >
                          {t('viewAll')}
                          <ArrowRight className="w-4 h-4" />
                        </Link>
                      </div>

                      <div className="grid gap-6 md:grid-cols-2">
                        {recentPosts.map((post: any) => (
                          <PostCard key={post.id} post={post} />
                        ))}
                      </div>

                      {recentPosts.length === 0 && (
                        <div className="text-center py-16 text-text-light dark:text-dark-text-muted">
                          <p className="text-lg mb-4">{t('noPosts')}</p>
                          <Link href="/editor" className="btn btn-primary">
                            {t('createPost')}
                          </Link>
                        </div>
                      )}
                    </div>

                    {/* Suggested Posts Carousel */}
                    <SuggestedPostsCarousel limit={6} />
                  </div>

                  {/* Sidebar Column */}
                  <div className="space-y-6">
                    {/* Activity Feed */}
                    <ActivityFeedCompact limit={5} />

                    {/* Related Authors */}
                    <div className="card p-4">
                      <RelatedAuthors currentUserId={user.id} limit={4} />
                    </div>
                  </div>
                </div>
              </div>
            </section>

            {/* Floating Action Button for Quick Actions */}
            <FloatingActionButton />
          </>
        ) : (
          <>
            {/* Hero Section for Non-logged-in Users - Asymmetric Editorial Layout */}
            <section className="min-h-[90vh] flex items-center bg-white">
              <div className="container-custom max-w-7xl py-20 md:py-28 lg:py-32">
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 lg:gap-16 items-center">
                  {/* Left Column - Content */}
                  <div className="space-y-8">
                    {/* Small Badge/Label */}
                    <div className="inline-flex items-center gap-2 px-3 py-1.5 bg-gray-100 rounded-lg">
                      <span className="text-xs font-medium uppercase tracking-wider text-gray-600">
                        {t('badge')}
                      </span>
                    </div>

                    {/* Large Headline */}
                    <h1 className="text-[3rem] md:text-[4rem] lg:text-[5rem] font-display font-bold leading-[0.95] tracking-tight text-gray-900">
                      {t('heroTitle')}
                    </h1>

                    {/* Subtitle */}
                    <p className="text-xl md:text-2xl text-gray-500 max-w-lg leading-relaxed">
                      {t('heroSubtitle')}
                    </p>

                    {/* CTA Buttons */}
                    <div className="flex flex-col sm:flex-row gap-4 pt-4">
                      <Link
                        href="/auth/signup"
                        className="inline-flex items-center justify-center gap-2 px-8 py-4 bg-[#DE5F43] hover:bg-[#c9533a] text-white font-semibold rounded-2xl transition-all duration-200 shadow-sm hover:shadow-md"
                      >
                        {t('getStarted')}
                        <ArrowRight className="w-5 h-5" />
                      </Link>
                      <Link
                        href="/explore"
                        className="inline-flex items-center justify-center gap-2 px-8 py-4 bg-gray-100 hover:bg-gray-200 text-gray-900 font-semibold rounded-2xl transition-all duration-200"
                      >
                        {t('browsePosts')}
                      </Link>
                    </div>

                    {/* Social Proof Stats */}
                    <div className="flex flex-wrap gap-8 pt-8 border-t border-gray-200">
                      <div>
                        <div className="text-3xl font-bold text-gray-900">500+</div>
                        <div className="text-sm text-gray-500">Researchers</div>
                      </div>
                      <div>
                        <div className="text-3xl font-bold text-gray-900">1,200+</div>
                        <div className="text-sm text-gray-500">Publications</div>
                      </div>
                      <div>
                        <div className="text-3xl font-bold text-gray-900">50+</div>
                        <div className="text-sm text-gray-500">Universities</div>
                      </div>
                    </div>
                  </div>

                  {/* Right Column - Hero Illustration */}
                  <div className="relative hidden lg:block">
                    <div className="aspect-[4/3] bg-gradient-to-br from-gray-50 to-gray-100 rounded-3xl overflow-hidden border border-gray-200">
                      {/* Decorative Elements */}
                      <div className="absolute inset-0 flex items-center justify-center">
                        <div className="grid grid-cols-2 gap-4 p-8 w-full max-w-md">
                          {/* Card 1 */}
                          <div className="bg-white rounded-2xl p-4 shadow-sm border border-gray-100">
                            <div className="w-8 h-8 bg-[#DE5F43]/10 rounded-lg mb-3 flex items-center justify-center">
                              <Sparkles className="w-4 h-4 text-[#DE5F43]" />
                            </div>
                            <div className="h-2 bg-gray-200 rounded w-3/4 mb-2"></div>
                            <div className="h-2 bg-gray-100 rounded w-1/2"></div>
                          </div>
                          {/* Card 2 */}
                          <div className="bg-white rounded-2xl p-4 shadow-sm border border-gray-100 mt-8">
                            <div className="w-8 h-8 bg-blue-50 rounded-lg mb-3 flex items-center justify-center">
                              <Search className="w-4 h-4 text-blue-500" />
                            </div>
                            <div className="h-2 bg-gray-200 rounded w-2/3 mb-2"></div>
                            <div className="h-2 bg-gray-100 rounded w-1/3"></div>
                          </div>
                          {/* Card 3 */}
                          <div className="bg-white rounded-2xl p-4 shadow-sm border border-gray-100 -mt-4">
                            <div className="w-8 h-8 bg-green-50 rounded-lg mb-3 flex items-center justify-center">
                              <Users className="w-4 h-4 text-green-500" />
                            </div>
                            <div className="h-2 bg-gray-200 rounded w-full mb-2"></div>
                            <div className="h-2 bg-gray-100 rounded w-2/3"></div>
                          </div>
                          {/* Card 4 */}
                          <div className="bg-white rounded-2xl p-4 shadow-sm border border-gray-100">
                            <div className="flex items-center gap-2 mb-3">
                              <div className="w-6 h-6 bg-gray-200 rounded-full"></div>
                              <div className="h-2 bg-gray-200 rounded w-16"></div>
                            </div>
                            <div className="h-2 bg-gray-100 rounded w-full mb-2"></div>
                            <div className="h-2 bg-gray-100 rounded w-3/4"></div>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </section>

            {/* Features Section */}
            <section className="section bg-background-light dark:bg-dark-surface/50">
              <div className="container-custom">
                <div className="text-center mb-16">
                  <h2 className="mb-4">{t('featuresTitle')}</h2>
                  <p className="text-lg text-text-light dark:text-dark-text-muted max-w-2xl mx-auto">
                    {t('featuresSubtitle')}
                  </p>
                </div>

                <div className="grid-auto max-w-5xl mx-auto">
                  {/* Feature 1 */}
                  <div className="card p-8 text-center group hover:shadow-soft-lg transition-all">
                    <div className="w-14 h-14 bg-primary/10 dark:bg-primary-light/20 rounded-xl flex items-center justify-center mx-auto mb-5 group-hover:scale-110 transition-transform">
                      <Sparkles className="w-7 h-7 text-primary dark:text-primary-light" />
                    </div>
                    <h3 className="text-xl font-display font-semibold mb-3">
                      {t('feature1Title')}
                    </h3>
                    <p className="text-text-light dark:text-dark-text-muted leading-relaxed">
                      {t('feature1Desc')}
                    </p>
                  </div>

                  {/* Feature 2 */}
                  <div className="card p-8 text-center group hover:shadow-soft-lg transition-all">
                    <div className="w-14 h-14 bg-accent/10 dark:bg-accent-light/20 rounded-xl flex items-center justify-center mx-auto mb-5 group-hover:scale-110 transition-transform">
                      <Search className="w-7 h-7 text-accent dark:text-accent-light" />
                    </div>
                    <h3 className="text-xl font-display font-semibold mb-3">
                      {t('feature2Title')}
                    </h3>
                    <p className="text-text-light dark:text-dark-text-muted leading-relaxed">
                      {t('feature2Desc')}
                    </p>
                  </div>

                  {/* Feature 3 */}
                  <div className="card p-8 text-center group hover:shadow-soft-lg transition-all">
                    <div className="w-14 h-14 bg-primary/10 dark:bg-primary-light/20 rounded-xl flex items-center justify-center mx-auto mb-5 group-hover:scale-110 transition-transform">
                      <Users className="w-7 h-7 text-primary dark:text-primary-light" />
                    </div>
                    <h3 className="text-xl font-display font-semibold mb-3">
                      {t('feature3Title')}
                    </h3>
                    <p className="text-text-light dark:text-dark-text-muted leading-relaxed">
                      {t('feature3Desc')}
                    </p>
                  </div>
                </div>
              </div>
            </section>

            {/* CTA Section */}
            <section className="section">
              <div className="container-narrow">
                <div className="card p-10 md:p-16 text-center bg-gradient-to-br from-primary/5 to-accent/5 dark:from-primary-light/10 dark:to-accent-light/10 border-primary/10 dark:border-primary-light/20">
                  <h2 className="mb-4">{t('ctaTitle')}</h2>
                  <p className="text-lg text-text-light dark:text-dark-text-muted max-w-xl mx-auto mb-8">
                    {t('ctaDesc')}
                  </p>
                  <Link href="/auth/signup" className="btn btn-primary px-8 py-4 text-lg inline-flex items-center gap-2">
                    {t('createAccount')}
                    <ArrowRight className="w-5 h-5" />
                  </Link>
                </div>
              </div>
            </section>
          </>
        )}
      </main>

      <Footer />
    </div>
  )
}
